                    </button>
                </header>
                <div className="p-4 md:p-6">
                    {renderPage()}
                </div>
            </main>
            {showPasswordModal && (
                <PasswordModal
                    onSuccess={(user) => {
                        setAuthenticatedUser(user);
                        setShowPasswordModal(false);
                        if (currentPage === 'settings' && user.role !== 'admin') {
                            setNotification({ message: 'ليس لديك صلاحية للوصول إلى هذه الصفحة.', type: 'error' });
