// Simplified timestamp helper strictly for TODAY'S dashboard view
const getTimestampFromItem = (item: RawTeacherAttendanceData): Date | null => {
    let timestamp: Date | null = null;
    const dateProcessValue = item['تاريخ العملية'];
    const timeProcessValue = item['وقت العملية'];

    const isValidDate = (d: any): d is Date => d instanceof Date && !isNaN(d.getTime());

    if (dateProcessValue && timeProcessValue) {
        try {
            const dateProcessStr = String(dateProcessValue);
            const timeProcessStr = String(timeProcessValue);

            let year: number, month: number, day: number;
            const dateMatch = dateProcessStr.match(/(\d{4})-(\d{1,2})-(\d{1,2})/);
            if (dateMatch) {
                year = Number(dateMatch[1]);
                month = Number(dateMatch[2]);
                day = Number(dateMatch[3]);
            } else {
                const d = new Date(dateProcessStr);
                if (!isValidDate(d)) return null; 
                year = d.getFullYear();
                month = d.getMonth() + 1;
                day = d.getDate();
            }
            if (year < 2023) return null;

            let hour: number, minute: number, second = 0;
            const timeMatch = timeProcessStr.match(/(\d{1,2}):(\d{1,2}):(\d{1,2})/);
            if (!timeMatch) return null;

            hour = parseInt(timeMatch[1], 10);
            minute = parseInt(timeMatch[2], 10);
            second = parseInt(timeMatch[3], 10);

            if (timeProcessStr.includes('م') && hour < 12) hour += 12;
            else if (timeProcessStr.includes('ص') && hour === 12) hour = 0;

            const localDate = new Date(year, month - 1, day, hour, minute, second);
            if (isValidDate(localDate)) timestamp = localDate;
        } catch (e) {}
    }
    return timestamp;
};

