    const dayOptions = Array.from(new Set<string>(dailyStudents.map(s => s.day).filter((d): d is string => !!d)))
        .sort((a, b) => parseDateFromDayString(b).getTime() - parseDateFromDayString(a).getTime());

    const targetDay = settings.default_student_count_day || (dayOptions.length > 0 ? dayOptions[0] : null);

    // 1. استخدام ورقة daily فقط (dailyStudents) والمطابقة مع اليوم المختار
    const dailyRowsForTargetDay = targetDay ? dailyStudents.filter(s => s.day === targetDay) : [];

    // 2. تجميع البيانات لكل طالب (اسم المستخدم) لحساب المتوسط
    // النتيجة: صف واحد لكل طالب يحتوي على متوسط نسبة حضوره
    const studentAttendanceAggregator = new Map<number, { sum: number, count: number }>();

    dailyRowsForTargetDay.forEach(row => {
        const username = row.username;
        const attendance = row.attendance; // القيمة من عمود "نسبة الحضور" مباشرة

        if (!studentAttendanceAggregator.has(username)) {
            studentAttendanceAggregator.set(username, { sum: 0, count: 0 });
        }

        const current = studentAttendanceAggregator.get(username)!;
        current.sum += attendance;
        current.count += 1;
    });

    // 3. حساب متوسط نسبة الحضور لكل طالب ثم المتوسط العام
    const studentAverageValues = Array.from(studentAttendanceAggregator.values()).map(v => v.sum / v.count);

