      totalReview,
      totalConsolidation,
      totalAchievement,
      avgAttendance: finalAvgAttendance,
    };

    return {
        stats: finalStats,
        targetDayLabel: targetDay || 'لم يحدد يوم',
    };
  }, [students, dailyStudents, settings]);

  return (
    <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-8">
