function calculateAverageAttendance() {
  const SHEET_NAME = 'daily';
  const COLUMN_NAME = 'نسبة الحضور';

  const ss = SpreadsheetApp.getActiveSpreadsheet();
  const sheet = ss.getSheetByName(SHEET_NAME);
  if (!sheet) throw new Error('Sheet "daily" not found');

  const data = sheet.getDataRange().getValues();
  const headers = data[0];
  const colIndex = headers.indexOf(COLUMN_NAME);

  if (colIndex === -1) {
    throw new Error('Column "نسبة الحضور" not found');
  }

  let sum = 0;
  let count = 0;

  for (let i = 1; i < data.length; i++) {
    const value = data[i][colIndex];

    if (typeof value === 'number' && !isNaN(value)) {
      sum += value;
      count++;
    }
  }

  const average = count > 0 ? sum / count : 0;

  Logger.log('عدد القيم: ' + count);
  Logger.log('متوسط نسبة الحضور: ' + average);

  return average;
}

