                                    ${getProgressBarHtml(student.attendance)}
                                </td>
                                <td>${student.totalPoints}</td>
                            </tr>
                        `).join('')}
                    </tbody>
                    <tfoot>
                        <tr>
                            <td colspan="6" class="print-page-footer">
